module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

parameter IDLE = 3'b000;
parameter PULSE_START = 3'b001;
parameter PULSE_END = 3'b010;

reg [2:0] state;

reg [2:0] next_state;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        state <= IDLE;
    end else begin
        state <= next_state;
    end
end

always @(*) begin
    case(state)
        IDLE: begin
            if (data_in == 1'b1 && ~data_in) begin
                next_state = PULSE_START;
            end else begin
                next_state = IDLE;
            end
        end
        PULSE_START: begin
            if (~data_in) begin
                next_state = PULSE_END;
            end else begin
                next_state = PULSE_START;
            end
        end
        PULSE_END: begin
            if (data_in) begin
                next_state = IDLE;
            end else begin
                next_state = PULSE_END;
            end
        end
        default: next_state = IDLE;
    endcase
end

always @(*) begin
    if ((state == PULSE_END) && (data_in == 1'b0)) begin
        data_out = 1'b1;
    end else begin
        data_out = 1'b0;
    end
end
endmodule
